// ========================================
// SELECT PRODUCT & CLEANUP
// ========================================
const fs = require('fs');
const path = require('path');

// 1. SELECT THE PRODUCT TO TEST
// Options: 'ERP' or 'Camp'
const SELECTED_PRODUCT = 'ERP';

// 2. CLEANUP PREVIOUS RESULTS
const resultsDir = 'C:/Users/veeramani/.gemini/antigravity/scratch/Automation Workflow/temp_results';
if (fs.existsSync(resultsDir)) {
  const files = fs.readdirSync(resultsDir);
  for (const file of files) {
    try {
      fs.unlinkSync(path.join(resultsDir, file));
    } catch (e) { /* ignore cleanup errors */ }
  }
} else {
  fs.mkdirSync(resultsDir, { recursive: true });
}

// 3. RETURN SELECTED PRODUCT DATA
const products = {
  'ERP': {
    product: 'ERP',
    folder: 'ERP',
    description: 'Run all ERP test scripts'
  },
  'Camp': {
    product: 'Camp',
    folder: 'CampAccomodation',
    description: 'Run all Camp Accommodation test scripts'
  }
};

return [{ json: products[SELECTED_PRODUCT] }];

const fs = require('fs');

// Get the product info from previous node
const items = $input.all();

if (!items || items.length === 0) {
  throw new Error('No input data received from Select Product node');
}

const firstItem = items[0];

if (!firstItem.json || typeof firstItem.json !== 'object') {
  throw new Error('Invalid data structure: json property must be an object');
}

const product = firstItem.json.product;
const folder = firstItem.json.folder;

if (!product || !folder) {
  throw new Error('Missing product or folder information');
}

const basePath = 'C:/Users/veeramani/desktop/playwright-mcp/tests';
const fullPath = `${basePath}/${folder}`;

const returnData = [];

try {
  // Check if directory exists
  if (!fs.existsSync(fullPath)) {
    return [{
      json: {
        product: product,
        folder: folder,
        error: `Directory not found: ${fullPath}`,
        fileCount: 0
      }
    }];
  }

  // Read all .spec.js files
  const allFiles = fs.readdirSync(fullPath);
  const testFiles = allFiles.filter(file => file.endsWith('.spec.js'));

  if (testFiles.length === 0) {
    return [{
      json: {
        product: product,
        folder: folder,
        error: 'No .spec.js test files found in directory',
        fileCount: 0,
        path: fullPath
      }
    }];
  }

  // Create an item for each test file
  for (const file of testFiles) {
    returnData.push({
      json: {
        product: product,
        folder: folder,
        filename: file,
        fullPath: `${fullPath}/${file}`,
        testPath: `tests/${folder}/${file}`
      }
    });
  }

  return returnData;

} catch (error) {
  return [{
    json: {
      product: product,
      folder: folder,
      error: `Error reading directory: ${error.message}`,
      fileCount: 0
    }
  }];
}

const { execSync } = require('child_process');
const item = $input.item.json;

// Check if there's an error from previous step
if (item.error) {
  return {
    json: {
      ...item,
      exitCode: -1,
      stdout: '',
      stderr: item.error,
      status: 'skipped'
    }
  };
}

const product = item.product;
const folder = item.folder;
const filename = item.filename;
const testPath = item.testPath;
const cmd = `npx playwright test "${testPath}"`;
const cwd = 'C:\\Users\\veeramani\\desktop\\playwright-mcp';

const startTime = new Date();

try {
  const stdout = execSync(cmd, { 
    cwd: cwd, 
    stdio: 'pipe',
    timeout: 300000 // 5 minutes timeout
  }).toString();

  const endTime = new Date();
  const duration = ((endTime - startTime) / 1000).toFixed(2);

  return {
    json: {
      ...item,
      exitCode: 0,
      stdout: stdout,
      stderr: '',
      status: 'passed',
      duration: `${duration}s`,
      timestamp: new Date().toISOString()
    }
  };
} catch (e) {
  const err = e;
  const endTime = new Date();
  const duration = ((endTime - startTime) / 1000).toFixed(2);

  return {
    json: {
      ...item,
      exitCode: err.status || 1,
      stdout: (err.stdout || '').toString(),
      stderr: (err.stderr || err.message || '').toString(),
      status: 'failed',
      duration: `${duration}s`,
      timestamp: new Date().toISOString()
    }
  };
}

const fs = require('fs');
const path = require('path');

// CRITICAL FIX: Use the data from the 'Run Playwright Test' node directly,
// NOT from the Slack Notification response (which is just an API status).
const testData = $node["Run Playwright Test"].json;
const resultsDir = 'C:/Users/veeramani/.gemini/antigravity/scratch/Automation Workflow/temp_results';

// Create directory if it doesn't exist
if (!fs.existsSync(resultsDir)) {
  fs.mkdirSync(resultsDir, { recursive: true });
}

// Save this test result with a timestamp to avoid collisions
const timestamp = Date.now();
const resultFile = path.join(resultsDir, `test_${timestamp}_${testData.filename}.json`);
fs.writeFileSync(resultFile, JSON.stringify(testData, null, 2));

// Check if test failed - strictly based on exitCode (0 = pass)
const exitCode = typeof testData.exitCode === 'number' ? testData.exitCode : parseInt(testData.exitCode || '0', 10);
const isFailed = (exitCode !== 0);

return [{ json: { ...testData, isFailed: isFailed } }];

const fs = require('fs');
const logDir = 'C:/Users/veeramani/.gemini/antigravity/scratch/Automation Workflow/logs';
const sourceData = $input.first().json;
const product = sourceData.product;
const scriptName = sourceData.filename;
const exitCode = sourceData.exitCode;
const stdOut = (sourceData.stdout || "").substring(0, 1000);
const stdErr = (sourceData.stderr || "").substring(0, 1000);
const duration = sourceData.duration || 'N/A';
const timestamp = new Date().toLocaleString();

// Create logs directory if it doesn't exist
if (!fs.existsSync(logDir)) {
  fs.mkdirSync(logDir, { recursive: true });
}

// Create product-specific log file
const logPath = `${logDir}/${product}_FAILURES.md`;

const logContent = `
## ❌ Test Failure Report
**Timestamp:** ${timestamp}
**Product:** ${product}
**Test Script:** \`${scriptName}\`
**Exit Code:** ${exitCode}
**Duration:** ${duration}

### Error Output:
\`\`\`
${stdErr || 'No error output'}
\`\`\`

### Standard Output:
\`\`\`
${stdOut || 'No standard output'}
\`\`\`

---
`;

if (!fs.existsSync(logPath)) {
  const header = `# 🐞 ${product} Test Failure Log\n\nThis file contains all test failures for the ${product} product.\n\n---\n`;
  fs.writeFileSync(logPath, header + logContent);
} else {
  fs.appendFileSync(logPath, logContent);
}

return $input.all();

const fs = require('fs');
const path = require('path');

// ========================================
// GENERATE SUMMARY FROM SAVED RESULTS
// ========================================

const resultsDir = 'C:/Users/veeramani/.gemini/antigravity/scratch/Automation Workflow/temp_results';
const testResults = [];
let product = 'Unknown';
let hasResults = false;

// Read all test result files
if (fs.existsSync(resultsDir)) {
  const files = fs.readdirSync(resultsDir).filter(f => f.startsWith('test_') && f.endsWith('.json'));

  if (files.length > 0) {
    hasResults = true;
    for (const file of files) {
      try {
        const filePath = path.join(resultsDir, file);
        const content = fs.readFileSync(filePath, 'utf8');
        const parsed = JSON.parse(content);
        testResults.push(parsed);

        // Capture the correct product name
        if (product === 'Unknown' && parsed.product) {
          product = parsed.product;
        }
      } catch (e) { /* ignore invalid files */ }
    }

    // Clean up temp files after reading
    for (const file of files) {
      try { fs.unlinkSync(path.join(resultsDir, file)); } catch (e) {}
    }
  }
}

if (!hasResults) {
  return [{ json: { skipSummary: true } }];
}

// Calculate statistics robustly
const total = testResults.length;
const passed = testResults.filter(t => {
  // Check status string OR exit code 0
  return t.status === 'passed' || t.exitCode === 0 || t.exitCode === "0";
}).length;
const failed = total - passed;
const successRate = total > 0 ? ((passed / total) * 100).toFixed(2) : 0;

// Calculate total duration
const totalDuration = testResults.reduce((sum, test) => {
  const durationStr = (test.duration || '0s').toString().replace('s', '');
  const duration = parseFloat(durationStr) || 0;
  return sum + duration;
}, 0).toFixed(2);

return [{ json: {
  skipSummary: false,
  product: product,
  total: total,
  passed: passed,
  failed: failed,
  successRate: `${successRate}%`,
  totalDuration: `${totalDuration}s`,
  timestamp: new Date().toISOString()
}}];
